using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public required string PredictedCategory { get; set; }
    public required Dictionary<string, float> Confidence { get; set; }
}

public class ModelMetricsResponse
{
    public float MicroAccuracy { get; set; }
    public float MacroAccuracy { get; set; }
    public float LogLoss { get; set; }
    public float LogLossReduction { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelTrainer
{
    private readonly MLContext _mlContext;
    private readonly ILogger<TicketModelTrainer> _logger;
    private readonly string _dataPath;
    private readonly string _modelPath;

    public TicketModelTrainer(ILogger<TicketModelTrainer> logger, IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public ModelMetricsResponse TrainAndEvaluate()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // With only 6 rows, use full dataset for training and evaluate on training set
        // to demonstrate the pipeline. In production, use TrainTestSplit with more data.
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(data);

        var predictions = model.Transform(data);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        _logger.LogInformation(
            "Model metrics — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
            metrics.MicroAccuracy, metrics.MacroAccuracy, metrics.LogLoss);

        _mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);

        return new ModelMetricsResponse
        {
            MicroAccuracy = (float)metrics.MicroAccuracy,
            MacroAccuracy = (float)metrics.MacroAccuracy,
            LogLoss = (float)metrics.LogLoss,
            LogLossReduction = (float)metrics.LogLossReduction
        };
    }

    public string ModelPath => _modelPath;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;
    private readonly TicketModelTrainer _trainer;

    public TicketController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool,
        TicketModelTrainer trainer)
    {
        _predictionPool = predictionPool;
        _trainer = trainer;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var labels = new[] { "Billing", "General", "Technical" };
        var confidence = labels
            .Zip(prediction.Score, (label, score) => new { label, score })
            .ToDictionary(x => x.label, x => x.score);

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }

    [HttpPost("train")]
    public ActionResult<ModelMetricsResponse> Train()
    {
        var metrics = _trainer.TrainAndEvaluate();
        return Ok(metrics);
    }
}

