using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<TicketModelTrainer>();

// Train the model before building so the file exists for the prediction pool.
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");

var mlContext = new MLContext(seed: 42);
var data = mlContext.Data.LoadFromTextFile<TicketData>(
    dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

var pipeline = mlContext.Transforms.Conversion
        .MapValueToKey("Label", nameof(TicketData.Category))
    .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
    .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
    .Append(mlContext.Transforms.Concatenate("Features",
        "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.MulticlassClassification.Trainers
        .SdcaMaximumEntropy("Label", "Features"))
    .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

var model = pipeline.Fit(data);

var predictions = model.Transform(data);
var metrics = mlContext.MulticlassClassification.Evaluate(predictions);
Console.WriteLine($"Model trained — MicroAccuracy: {metrics.MicroAccuracy:F4}, " +
                  $"MacroAccuracy: {metrics.MacroAccuracy:F4}, LogLoss: {metrics.LogLoss:F4}");

mlContext.Model.Save(model, data.Schema, modelPath);

builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

